import React from 'react';
import { MapContainer, TileLayer, Polyline, Marker, Popup } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';

// Fix for default Leaflet icons
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon-2x.png',
  iconUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon.png',
  shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-shadow.png',
});

const MapDisplay = ({ waypoints, source, destination }) => {
  const center = source ? [source.lat, source.lng] : [28.6139, 77.2090];

  return (
    <MapContainer center={center} zoom={13} style={{ height: '100%', width: '100%' }} zoomControl={false}>
      <TileLayer url="https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png" />
      
      {source && <Marker position={[source.lat, source.lng]}><Popup>Start</Popup></Marker>}
      {destination && <Marker position={[destination.lat, destination.lng]}><Popup>End</Popup></Marker>}

      {waypoints.length > 0 && (
        <Polyline 
          positions={waypoints.map(p => [p.lat, p.lng])} 
          pathOptions={{ color: '#7c3aed', weight: 5, opacity: 0.7, lineJoin: 'round' }} 
        />
      )}
    </MapContainer>
  );
};

export default MapDisplay;
